import { Select as SelectPrimitive } from "@base-ui/react/select";
import { CaretDownIcon, CaretUpIcon, CheckIcon } from "@phosphor-icons/react";
import * as stylex from "@stylexjs/stylex";
import type * as React from "react";
import { Field, FieldError, FieldLabel } from "../Field/field";
import { selectStyles } from "./select.styles";

type SelectSize = "sm" | "default" | "lg";

type SelectItemProp = string | number | { label: React.ReactNode; value: unknown };

interface SelectRootProps extends SelectPrimitive.Root.Props<SelectItemProp> {}

export function SelectRoot({ children, ...props }: SelectRootProps) {
  return <SelectPrimitive.Root {...props}>{children}</SelectPrimitive.Root>;
}

export function SelectLabel(props: SelectPrimitive.Label.Props) {
  return <SelectPrimitive.Label {...stylex.props(selectStyles.label)} {...props} />;
}

export function SelectTrigger({
  size = "default",
  ...props
}: SelectPrimitive.Trigger.Props & { size?: SelectSize }) {
  return (
    <SelectPrimitive.Trigger
      {...stylex.props(
        selectStyles.trigger,
        size === "sm" && selectStyles.triggerSm,
        size === "lg" && selectStyles.triggerLg,
      )}
      {...props}
    />
  );
}

export function SelectValue({ placeholder, ...props }: SelectPrimitive.Value.Props) {
  return <SelectPrimitive.Value placeholder={placeholder} {...props} />;
}

export function SelectIcon(props: SelectPrimitive.Icon.Props) {
  return (
    <SelectPrimitive.Icon {...stylex.props(selectStyles.icon)} {...props}>
      <CaretDownIcon size={16} />
    </SelectPrimitive.Icon>
  );
}

export function SelectPortal(props: SelectPrimitive.Portal.Props) {
  return <SelectPrimitive.Portal {...props} />;
}

export function SelectPositioner({ sideOffset = 4, ...props }: SelectPrimitive.Positioner.Props) {
  return <SelectPrimitive.Positioner sideOffset={sideOffset} {...props} />;
}

export function SelectPopup(props: SelectPrimitive.Popup.Props) {
  return <SelectPrimitive.Popup {...stylex.props(selectStyles.popup)} {...props} />;
}

export function SelectList(props: SelectPrimitive.List.Props) {
  return <SelectPrimitive.List {...props} />;
}

export function SelectItem({
  children,
  ...props
}: SelectPrimitive.Item.Props & { children: React.ReactNode }) {
  return (
    <SelectPrimitive.Item {...stylex.props(selectStyles.item)} {...props}>
      <SelectPrimitive.ItemIndicator {...stylex.props(selectStyles.itemIndicator)}>
        <CheckIcon size={14} weight="bold" />
      </SelectPrimitive.ItemIndicator>
      <SelectPrimitive.ItemText>{children}</SelectPrimitive.ItemText>
    </SelectPrimitive.Item>
  );
}

export function SelectSeparator(props: SelectPrimitive.Separator.Props) {
  return <SelectPrimitive.Separator {...stylex.props(selectStyles.separator)} {...props} />;
}

export function SelectGroup(props: SelectPrimitive.Group.Props) {
  return <SelectPrimitive.Group {...props} />;
}

export function SelectGroupLabel(props: SelectPrimitive.GroupLabel.Props) {
  return <SelectPrimitive.GroupLabel {...stylex.props(selectStyles.groupLabel)} {...props} />;
}

export function SelectScrollUpArrow(props: SelectPrimitive.ScrollUpArrow.Props) {
  return (
    <SelectPrimitive.ScrollUpArrow {...stylex.props(selectStyles.scrollArrow)} {...props}>
      <CaretUpIcon size={12} />
    </SelectPrimitive.ScrollUpArrow>
  );
}

export function SelectScrollDownArrow(props: SelectPrimitive.ScrollDownArrow.Props) {
  return (
    <SelectPrimitive.ScrollDownArrow {...stylex.props(selectStyles.scrollArrow)} {...props}>
      <CaretDownIcon size={12} />
    </SelectPrimitive.ScrollDownArrow>
  );
}

// ─── Convenience wrapper ──────────────────────────────────────────────────────

interface SelectWrapperProps {
  label?: string;
  error?: string;
  children: React.ReactNode;
}

export function SelectWrapper({ label, error, children }: SelectWrapperProps) {
  return (
    <Field invalid={!!error}>
      {label && <FieldLabel>{label}</FieldLabel>}
      {children}
      {error && <FieldError>{error}</FieldError>}
    </Field>
  );
}

// ─── Compound component namespace ─────────────────────────────────────────────

export const Select = {
  Root: SelectRoot,
  Label: SelectLabel,
  Trigger: SelectTrigger,
  Value: SelectValue,
  Icon: SelectIcon,
  Portal: SelectPortal,
  Positioner: SelectPositioner,
  Popup: SelectPopup,
  List: SelectList,
  Item: SelectItem,
  Separator: SelectSeparator,
  Group: SelectGroup,
  GroupLabel: SelectGroupLabel,
  ScrollUpArrow: SelectScrollUpArrow,
  ScrollDownArrow: SelectScrollDownArrow,
  Wrapper: SelectWrapper,
};

import * as stylex from "@stylexjs/stylex";
import { borderRadius, fontSize, fontWeight, spacing, theme } from "@/lib/theme/contract.stylex";

export const selectStyles = stylex.create({
  label: {
    fontSize: fontSize.xsmall,
    fontWeight: fontWeight.semibold,
    color: theme.contentSecondary,
    paddingBottom: spacing.xsmall,
    paddingLeft: spacing.xsmall,
    paddingRight: spacing.xsmall,
  },

  trigger: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    gap: spacing.small,
    boxSizing: "border-box",
    width: "100%",
    paddingTop: spacing.small,
    paddingBottom: spacing.small,
    paddingLeft: spacing.medium,
    paddingRight: spacing.small,
    fontSize: fontSize.small,
    lineHeight: "1.5",
    fontFamily: "inherit",
    color: theme.contentPrimary,
    backgroundColor: theme.surface,
    borderWidth: 1,
    borderStyle: "solid",
    borderColor: theme.border,
    borderRadius: borderRadius.medium,
    outline: "none",
    cursor: "pointer",
    transition: "border-color 0.15s ease, box-shadow 0.15s ease",
    ":hover": {
      borderColor: theme.borderStrong,
    },
    ":focus-visible": {
      borderColor: theme.primary,
      boxShadow: `0 0 0 2px ${theme.focusRing}`,
    },
    ":disabled": {
      opacity: 0.5,
      cursor: "not-allowed",
    },
    "[data-placeholder]": {
      color: theme.contentDisabled,
    },
  },

  triggerSm: {
    paddingTop: spacing.xsmall,
    paddingBottom: spacing.xsmall,
    paddingLeft: spacing.small,
    paddingRight: spacing.xsmall,
    fontSize: 14,
  },

  triggerLg: {
    paddingTop: spacing.medium,
    paddingBottom: spacing.medium,
    paddingLeft: spacing.large,
    paddingRight: spacing.medium,
    fontSize: 16,
  },

  icon: {
    display: "flex",
    alignItems: "center",
    color: theme.contentSecondary,
    flexShrink: 0,
  },

  popup: {
    boxSizing: "border-box",
    minWidth: "100%",
    maxHeight: 300,
    paddingTop: spacing.xsmall,
    paddingBottom: spacing.xsmall,
    backgroundColor: theme.surface,
    borderWidth: 1,
    borderStyle: "solid",
    borderColor: theme.border,
    borderRadius: borderRadius.large,
    boxShadow: theme.shadowLg,
    zIndex: 1400,
    outline: "none",
    overflowY: "auto",
    ":focus-visible": {
      outline: "none",
    },
  },

  item: {
    display: "flex",
    alignItems: "center",
    gap: spacing.small,
    boxSizing: "border-box",
    minHeight: 32,
    paddingTop: spacing.xsmall,
    paddingBottom: spacing.xsmall,
    paddingLeft: spacing.small,
    paddingRight: spacing.small,
    marginLeft: spacing.xsmall,
    marginRight: spacing.xsmall,
    borderRadius: borderRadius.small,
    fontSize: fontSize.small,
    lineHeight: "1.4",
    color: theme.contentPrimary,
    cursor: "pointer",
    userSelect: "none",
    ":hover": {
      backgroundColor: theme.backgroundSubtle,
    },
    "[data-highlighted]": {
      backgroundColor: theme.backgroundSubtle,
    },
    "[data-selected]": {
      backgroundColor: theme.primary,
      color: theme.contentOnPrimary,
      ":hover": {
        backgroundColor: theme.primary,
      },
      "[data-highlighted]": {
        backgroundColor: theme.primary,
      },
    },
    "[data-disabled]": {
      color: theme.contentDisabled,
      cursor: "default",
      ":hover": {
        backgroundColor: "transparent",
      },
    },
  },

  itemIndicator: {
    display: "inline-flex",
    alignItems: "center",
    flexShrink: 0,
    width: 14,
  },

  separator: {
    height: 1,
    marginTop: spacing.xsmall,
    marginBottom: spacing.xsmall,
    backgroundColor: theme.borderSubtle,
  },

  groupLabel: {
    paddingTop: spacing.small,
    paddingBottom: spacing.xsmall,
    paddingLeft: spacing.small,
    paddingRight: spacing.small,
    fontSize: fontSize.xsmall,
    fontWeight: fontWeight.semibold,
    color: theme.contentSecondary,
  },

  scrollArrow: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    width: "100%",
    height: 24,
    color: theme.contentSecondary,
    cursor: "pointer",
    ":hover": {
      backgroundColor: theme.backgroundSubtle,
    },
  },
});
